import json

# Get the list of article IDs from previous query
articles_data = locals()['var_functions.query_db:2']
article_ids = [article['article_id'] for article in articles_data]

# Create query with all article IDs
filter_query = {
    'article_id': {'$in': article_ids}
}

# Convert to JSON string for the tool
query_dict = {
    'collection': 'articles',
    'filter': filter_query,
    'projection': {'article_id': 1, 'title': 1, 'description': 1}
}

# We need to batch this since 111 articles might be too many for a single response
# Let's process in batches of 50
batch_size = 50
batches = []
for i in range(0, len(article_ids), batch_size):
    batch = article_ids[i:i+batch_size]
    batches.append(batch)

result_json = json.dumps({
    'total_articles': len(article_ids),
    'num_batches': len(batches),
    'first_batch_size': len(batches[0]) if batches else 0
})

print('__RESULT__:')
print(result_json)

